## 一、Hook 代码（`message:preprocessed`）

**文件**：`~/.openclaw/extensions/auto-router/index.js`

```javascript
const axios = require('axios');

const CLASSIFIER_URL = process.env.CLASSIFIER_URL || 'http://localhost:3104/classify';

const SCENE_TO_AGENT = {
    code_generation: 'executor',
    task_multi_step: 'executor',
    high_risk_automated: 'executor',
    math_reasoning: 'planner',
    expert_user: 'planner',
    fault_recovery: 'planner',
};
const DEFAULT_AGENT = 'executor';

/**
 * 调用分类器获取场景
 */
async function classify(message) {
    try {
        const res = await axios.post(CLASSIFIER_URL, { text: message }, { timeout: 500 });
        return res.data.label || 'vague_request';
    } catch (e) {
        return null;
    }
}

/**
 * 判断是否为任务型场景
 */
function isTaskScene(scene) {
    const taskScenes = ['code_generation', 'task_multi_step', 'high_risk_automated', 
                        'math_reasoning', 'expert_user', 'fault_recovery'];
    return taskScenes.includes(scene);
}

/**
 * 主 Hook 函数
 */
exports.messagePreprocessed = async function(event) {
    const userMessage = event.context?.bodyForAgent;
    const parentSessionKey = event.context?.sessionKey;  // 获取当前 session 的唯一标识

    if (!userMessage) return;

    // 1. 调用分类器
    const scene = await classify(userMessage);
    if (!scene || !isTaskScene(scene)) {
        return; // 非任务，让主 Agent 正常处理
    }

    // 2. 确定目标 Agent
    const targetAgent = SCENE_TO_AGENT[scene] || DEFAULT_AGENT;

    // 3. 构造派发指令，注入到 bodyForAgent
    const spawnInstruction = `
[系统指令 - 最高优先级]
请立即使用 sessions_spawn 工具派发一个子 Agent 来处理以下任务。

参数：
- agentId: ${targetAgent}
- message: "${userMessage.replace(/"/g, '\\"')}"
- metadata: { "parentSessionKey": "${parentSessionKey}", "originalTask": "${userMessage.replace(/"/g, '\\"')}" }

派发完成后，你的本轮回复仅输出：
"[系统] 任务已派发给子 Agent (${targetAgent})，请等待执行结果。"
不得输出任何其他内容。

[原始用户消息]
${userMessage}
`;

    event.context.bodyForAgent = spawnInstruction;
    console.log(`[auto-router] Injected spawn instruction for agent: ${targetAgent}`);
};
```

