## 一、Hook 代码（`message_preprocess`）

**文件位置**：`~/.openclaw/extensions/auto-router/index.js`（若目录不存在，请先创建）

```javascript
const fs = require('fs').promises;
const path = require('path');
const axios = require('axios');

const CLASSIFIER_URL = process.env.CLASSIFIER_URL || 'http://localhost:3104/classify';
const SCORER_URL = process.env.SCORER_URL || 'http://localhost:3103/api/score';
const GATEWAY_URL = process.env.GATEWAY_URL || 'http://localhost:3102';
const HOME = process.env.HOME || '/home/ai';

// 正确的 context.json 路径
const CONTEXT_PATH = path.join(HOME, '.openclaw/sessions/agent:main:main/context.json');

// 场景到 Agent 的映射
const SCENE_TO_AGENT = {
    code_generation: 'executor',
    task_multi_step: 'executor',
    high_risk_automated: 'executor',
    math_reasoning: 'planner',
    expert_user: 'planner',
    fault_recovery: 'planner',
};
const DEFAULT_AGENT = 'executor';

/**
 * 调用分类器
 */
async function classify(message) {
    try {
        const res = await axios.post(CLASSIFIER_URL, { text: message }, { timeout: 500 });
        return res.data.label || 'vague_request';
    } catch (e) {
        console.error('[auto-router] Classifier failed:', e.message);
        return null;
    }
}

/**
 * 调用评分器
 */
async function score(message) {
    try {
        const res = await axios.post(SCORER_URL, { prompt: message }, { timeout: 2000 });
        return res.data;
    } catch (e) {
        console.error('[auto-router] Scorer failed:', e.message);
        return null;
    }
}

/**
 * 派发子 Agent（通过 Gateway API）
 */
async function spawnSubagent(agentId, message) {
    try {
        const res = await axios.post(`${GATEWAY_URL}/api/sessions/spawn`, {
            agentId,
            message,
            isolated: true
        }, { timeout: 5000 });
        return res.data;
    } catch (e) {
        console.error('[auto-router] Failed to spawn subagent:', e.message);
        return null;
    }
}

/**
 * 写入委托标记到 context.json
 */
async function writeDelegationMarker(targetAgent) {
    try {
        // 确保目录存在
        await fs.mkdir(path.dirname(CONTEXT_PATH), { recursive: true });

        // 读取现有 context
        let context = {};
        try {
            const content = await fs.readFile(CONTEXT_PATH, 'utf8');
            context = JSON.parse(content);
        } catch (e) {
            // 文件不存在或为空，使用空对象
        }

        // 写入标记
        if (!context.metadata) context.metadata = {};
        context.metadata._subagentDelegated = true;
        context.metadata._targetAgent = targetAgent;
        context.metadata._delegatedAt = new Date().toISOString();

        await fs.writeFile(CONTEXT_PATH, JSON.stringify(context, null, 2));
        console.log(`[auto-router] Delegation marker written to ${CONTEXT_PATH}`);
        return true;
    } catch (e) {
        console.error('[auto-router] Failed to write context.json:', e.message);
        return false;
    }
}

/**
 * 判断是否为任务型场景
 */
function isTaskScene(scene) {
    const taskScenes = ['code_generation', 'task_multi_step', 'high_risk_automated', 
                        'math_reasoning', 'expert_user', 'fault_recovery'];
    return taskScenes.includes(scene);
}

/**
 * 主 Hook 函数
 */
export async function message_preprocess(ctx) {
    const userMessage = ctx.message.content;
    if (!userMessage) return ctx;

    // 1. 调用分类器
    const scene = await classify(userMessage);
    if (!scene || !isTaskScene(scene)) {
        // 非任务场景，让主 Agent 正常处理
        return ctx;
    }

    // 2. 调用评分器（可选，用于辅助决策）
    const scoring = await score(userMessage);
    ctx.logger.debug({ scene, scoring }, '[auto-router] Task detected');

    // 3. 确定目标 Agent
    const targetAgent = SCENE_TO_AGENT[scene] || DEFAULT_AGENT;

    // 4. 派发子 Agent
    const spawnResult = await spawnSubagent(targetAgent, userMessage);
    if (!spawnResult) {
        ctx.logger.warn('[auto-router] Subagent spawn failed, falling back to main agent');
        return ctx;
    }

    // 5. 写入委托标记
    await writeDelegationMarker(targetAgent);

    ctx.logger.info({ targetAgent, sessionId: spawnResult.sessionId }, '[auto-router] Task delegated');
    return ctx;
}
```

